Data.data:
.leaf-fall {
  animation: leaf-fall 15s linear infinite;
  animation-play-state: running;
}
.sunlight-glow {
  animation: sunlight-glow 4s ease-in-out infinite;
}
.ripple {
  animation: ripple-effect 0.6s ease-out;
}
.gentle-grow {
  animation: gentle-grow 0.2s ease-out;
  animation-fill-mode: forwards;
}
.page-transition {
  animation: page-transition 0.4s ease-out;
}
@-moz-keyframes leaf-fall {
  0% {
    transform: translateY(-100px) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.8;
  }
  90% {
    opacity: 0.6;
  }
  100% {
    transform: translateY(calc(100vh + 100px)) rotate(360deg);
    opacity: 0;
  }
}
@-webkit-keyframes leaf-fall {
  0% {
    transform: translateY(-100px) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.8;
  }
  90% {
    opacity: 0.6;
  }
  100% {
    transform: translateY(calc(100vh + 100px)) rotate(360deg);
    opacity: 0;
  }
}
@-o-keyframes leaf-fall {
  0% {
    transform: translateY(-100px) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.8;
  }
  90% {
    opacity: 0.6;
  }
  100% {
    transform: translateY(calc(100vh + 100px)) rotate(360deg);
    opacity: 0;
  }
}
@keyframes leaf-fall {
  0% {
    transform: translateY(-100px) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.8;
  }
  90% {
    opacity: 0.6;
  }
  100% {
    transform: translateY(calc(100vh + 100px)) rotate(360deg);
    opacity: 0;
  }
}
@-moz-keyframes sunlight-glow {
