  --text-accent-rgb: 242, 177, 56;
  --text-link-rgb: 242, 177, 56;
  --text-heading-rgb: 169, 196, 169;
  --text-primary-rgb: 240, 240, 230;
  --bg-sidebar-dark-rgb: 28, 61, 46;
  --bg-card-light-rgb: 20, 28, 14;
  --bg-card-rgb: 20, 28, 14;
}
body {
  background-color: var(--bg-deep);
  background-image: var(--bg-image) !important;
  background-attachment: fixed;
  background-size: cover;
  background-position: center;
  color: var(--text-primary);
  transition: background-color 0.3s ease, color 0.3s ease;
  min-height: 100vh;
  font-family: 'Noto Sans SC', 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  line-height: 1.7;
}
body::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0,0,0,0.2);
  z-index: -1;
  pointer-events: none;
  transition: background-color 0.3s ease;
}
.forest-theme-toggle {
  position: fixed;
  top: 20px;
  right: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 2.5rem;
  min-height: 2.5rem;
  border-radius: 4px;
  background-color: rgba(0,0,0,0.15);
  color: var(--text-nav);
  border: 1px solid rgba(255,255,255,0.2);
  font-size: 1.8rem;
  cursor: pointer;
  padding: 0.4rem 0.6rem;
  transition: all 0.3s ease;
  z-index: 1000;
}
.forest-theme-toggle:hover {
  background-color: rgba(0,0,0,0.25);
  color: var(--text-accent);
  transform: translateY(-1px);
}
.forest-theme-toggle:active {
  transform: translateY(0);
}
@media (max-width: 768px) {
  .forest-theme-toggle {
    top: 10px;
    right: 10px;
    font-size: 1.4rem;
    min-width: 2rem;
    min-height: 2rem;
    padding: 0.3rem 0.5rem;
  }
}
.forest-particles-canvas {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 0;
  opacity: var(--particle-opacity, 0.6);
  transition: opacity 0.5s ease;
