/**
 * 森林音频环境系统
 * 提供环境音效管理，支持森林音效、专注音效和交互反馈
 * 默认静音，用户可手动启用
 */

const ForestAudio = {
  // 配置
  config: {
    enabled: false, // 默认静音
    masterVolume: 0.5,
    sounds: {
      // 音效定义 - 路径相对于站点根目录
      birds: {
        name: '鸟鸣',
        path: '/audio/birds.mp3',
        volume: 0.4,
        loop: true,
        description: '清晨森林鸟鸣声'
      },
      wind: {
        name: '风声', 
        path: '/audio/wind.mp3',
        volume: 0.2,  // 降低音量，避免风声音效过长过大
        loop: true,
        description: '轻柔的森林微风'
      },
      leaves: {
        name: '树叶声',
        path: '/audio/leaves.mp3',
        volume: 0.2,
        loop: true,
        description: '树叶沙沙声'
      },
      rain: {
        name: '雨声',
        path: '/audio/rain.mp3', 
        volume: 0.6,
        loop: true,
        description: '舒缓的雨声'
      },
      stream: {
        name: '溪流声',
        path: '/audio/stream.mp3',
        volume: 0.5,
        loop: true,
        description: '山间溪流声'
      },
      click: {
        name: '点击反馈',
        path: '/audio/click.mp3',
        volume: 0.1,
        loop: false,
        description: '点击交互音效'
      },
      achievement: {
        name: '成就解锁',
        path: '/audio/achievement.mp3',
        volume: 0.3,
        loop: false,
        description: '成就解锁庆祝音效'
      }
    }
  },

  // 状态
  audioContext: null,
  sounds: {},
  gainNodes: {},
  loadingPromises: {}, // 跟踪正在加载的音频Promise
  isInitialized: false,
  isPlaying: false,

  // 初始化音频系统
  init() {
    console.log('🎧 开始初始化音频系统...');
    if (this.isInitialized) {
      console.log('🎧 音频系统已初始化');
      return;
    }

    // 读取全局配置
    if (window.FOREST_AUDIO_CONFIG) {
      this.config.enabled = window.FOREST_AUDIO_CONFIG.enabled;
      console.log('🎧 使用配置中的音频设置');
    }

    // 检查浏览器支持
    const audioContextSupported = !!(window.AudioContext || window.webkitAudioContext);
    const getUserMediaSupported = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia);

    if (!audioContextSupported) {
      console.warn('🎧 浏览器不支持Web Audio API，音频功能不可用');
      this.showUnsupportedMessage();
      this.config.enabled = false;
      return;
    }

    // 创建音频上下文
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    this.audioContext = new AudioContextClass();

    // 检查自动播放策略
    if (typeof this.audioContext.resume !== 'function') {
      console.warn('🎧 音频上下文不支持resume()，移动端体验可能受限');
    }

    // 加载用户偏好
    this.loadPreferences();

    // 创建主音量控制
    this.createMasterGain();

    // 预加载音效（懒加载，实际使用时加载）
    this.setupSoundBuffers();

    this.isInitialized = true;
    console.log('🎧 森林音频系统已初始化');

    // 预加载常用音效
    this.preloadPrioritySounds();

    // 如果用户启用了音频，则开始播放环境音效
    if (this.config.enabled) {
      this.startAmbientSounds();
    }

    // 创建UI控制面板
    this.createAudioControls();

    // 设置页面可见性变化处理和快捷键
    this.setupVisibilityHandler();
  },

  // 显示不支持消息
  showUnsupportedMessage() {
    const toggleBtn = document.getElementById('forest-audio-toggle');
    if (toggleBtn) {
      toggleBtn.style.display = 'none';
    }

    // 可选：在控制台显示更详细的信息
    console.info('🎧 音频功能需要Web Audio API支持，当前浏览器不支持此功能');
  },

  // 加载用户偏好设置
  loadPreferences() {
    try {
      const savedSettings = localStorage.getItem('forest-audio-settings');
      if (savedSettings) {
        this.userSettings = JSON.parse(savedSettings);

        // 应用保存的设置
        if (this.userSettings.enabled !== undefined) {
          this.config.enabled = this.userSettings.enabled;
        }

        if (this.userSettings.masterVolume !== undefined) {
          this.config.masterVolume = this.userSettings.masterVolume;
        }

        if (this.userSettings.enabledSounds) {
          // 音效启用状态已从存储中加载，将在UI初始化时应用
        }

        if (this.userSettings.soundVolumes) {
          // 更新音效音量
          Object.entries(this.userSettings.soundVolumes).forEach(([soundId, volume]) => {
            if (this.config.sounds[soundId]) {
              this.config.sounds[soundId].volume = volume;
            }
          });
        }

        console.log('🎧 用户音频设置已加载');
      } else {
        this.userSettings = {
          enabled: this.config.enabled,
          masterVolume: this.config.masterVolume,
          enabledSounds: {},
          soundVolumes: {}
        };
      }
    } catch (error) {
      console.warn('🎧 加载音频设置失败，使用默认设置', error);
      this.userSettings = {
        enabled: this.config.enabled,
        masterVolume: this.config.masterVolume,
        enabledSounds: {},
        soundVolumes: {}
      };
    }
  },

  // 保存用户设置
  saveSettings() {
    if (!this.userSettings) return;

    // 更新当前状态到用户设置
    this.userSettings.enabled = this.config.enabled;
    this.userSettings.masterVolume = this.config.masterVolume;

    // 更新音效启用状态
    if (!this.userSettings.enabledSounds) {
      this.userSettings.enabledSounds = {};
    }

    Object.keys(this.config.sounds).forEach(soundId => {
      const soundItem = document.querySelector(`[data-sound-id="${soundId}"]`);
      if (soundItem) {
        const isEnabled = soundItem.querySelector('.sound-checkbox').classList.contains('checked');
        this.userSettings.enabledSounds[soundId] = isEnabled;
      }
    });

    // 更新音效音量
    if (!this.userSettings.soundVolumes) {
      this.userSettings.soundVolumes = {};
    }

    Object.entries(this.config.sounds).forEach(([soundId, soundConfig]) => {
      this.userSettings.soundVolumes[soundId] = soundConfig.volume;
    });

    // 保存最后状态
    this.userSettings.lastState = this.isPlaying ? 'playing' : 'paused';

    try {
      localStorage.setItem('forest-audio-settings', JSON.stringify(this.userSettings));
    } catch (error) {
      console.warn('🎧 保存音频设置失败', error);
    }
  },

  // 创建主音量控制
  createMasterGain() {
    if (!this.audioContext) return;

    this.masterGainNode = this.audioContext.createGain();
    this.masterGainNode.gain.value = this.config.masterVolume;
    this.masterGainNode.connect(this.audioContext.destination);

    // 所有音效将在setupSoundBuffers中连接到主增益节点
  },

  // 设置音效缓冲区（懒加载）
  setupSoundBuffers() {
    this.sounds = {};
    this.gainNodes = {};

    Object.keys(this.config.sounds).forEach(soundId => {
      this.sounds[soundId] = null; // null表示未加载
      this.gainNodes[soundId] = this.audioContext.createGain();
      this.gainNodes[soundId].gain.value = this.config.sounds[soundId].volume;
      this.gainNodes[soundId].connect(this.masterGainNode);
    });
  },

  // 加载音效（带懒加载队列）
  loadSound(soundId, priority = 'normal') {
    // 如果已经在加载队列中，返回现有Promise
    if (this.loadingPromises[soundId]) {
      return this.loadingPromises[soundId];
    }

    const loadPromise = new Promise((resolve, reject) => {
      if (!this.config.sounds[soundId]) {
        reject(new Error(`音效不存在: ${soundId}`));
        return;
      }

      // 如果已经加载，直接返回
      if (this.sounds[soundId]) {
        resolve(this.sounds[soundId]);
        return;
      }

      const soundConfig = this.config.sounds[soundId];
      const audioPath = soundConfig.path;

      // 使用XMLHttpRequest加载音频（规范要求）
      const request = new XMLHttpRequest();
      request.open('GET', audioPath, true);
      request.responseType = 'arraybuffer';

      request.onload = () => {
        if (request.status === 200) {
          this.audioContext.decodeAudioData(request.response, (buffer) => {
            this.sounds[soundId] = {
              buffer: buffer,
              config: soundConfig,
              source: null
            };
            console.log(`🎧 音效加载成功: ${soundConfig.name}`);
            resolve(this.sounds[soundId]);
          }, (error) => {
            console.warn(`🎧 解码音频失败，使用占位符: ${error}`);
            const placeholderBuffer = this.generatePlaceholderSound(soundId);
            this.sounds[soundId] = {
              buffer: placeholderBuffer,
              config: soundConfig,
              source: null
            };
            resolve(this.sounds[soundId]);
          });
        } else {
          console.warn(`🎧 加载音频失败，使用占位符: ${request.status}`);
          const placeholderBuffer = this.generatePlaceholderSound(soundId);
          this.sounds[soundId] = {
            buffer: placeholderBuffer,
            config: soundConfig,
            source: null
          };
          resolve(this.sounds[soundId]);
        }
      };

      request.onerror = () => {
        console.warn(`🎧 网络错误，无法加载音频，使用占位符`);
        const placeholderBuffer = this.generatePlaceholderSound(soundId);
        this.sounds[soundId] = {
          buffer: placeholderBuffer,
          config: soundConfig,
          source: null
        };
        resolve(this.sounds[soundId]);
      };

      request.send();
    });

    this.loadingPromises[soundId] = loadPromise;

    // 加载完成后清理Promise引用
    loadPromise.finally(() => {
      delete this.loadingPromises[soundId];
    });

    return loadPromise;
  },

  // 预加载常用音效
  preloadPrioritySounds() {
    const prioritySounds = ['click', 'achievement'];
    prioritySounds.forEach(soundId => {
      this.loadSound(soundId, 'high').catch(() => {
        console.warn(`🎧 预加载音效失败: ${soundId}`);
      });
    });
  },

  // 生成占位符音效（简单合成音效）
  generatePlaceholderSound(soundId) {
    const buffer = this.audioContext.createBuffer(1, this.audioContext.sampleRate * 2, this.audioContext.sampleRate);
    const data = buffer.getChannelData(0);

    // 根据音效类型生成不同的声音
    switch(soundId) {
      case 'birds':
        // 鸟鸣：短促的啾啾声
        for (let i = 0; i < data.length; i++) {
          const t = i / this.audioContext.sampleRate;
          // 随机产生鸟鸣声
          if (Math.random() < 0.002) { // 提高鸟鸣频率
            const freq = 800 + Math.random() * 800;
            const duration = 0.1 + Math.random() * 0.2;
            for (let j = 0; j < duration * this.audioContext.sampleRate && i + j < data.length; j++) {
              const t2 = j / this.audioContext.sampleRate;
              data[i + j] = 0.5 * Math.sin(2 * Math.PI * freq * t2) * Math.exp(-t2 * 10);
            }
            i += duration * this.audioContext.sampleRate;
          }
        }
        break;

      case 'wind':
        // 风声：低频噪声
        for (let i = 0; i < data.length; i++) {
          data[i] = (Math.random() * 2 - 1) * 0.5;
        }
        break;

      case 'rain':
        // 雨声：随机滴答声
        for (let i = 0; i < data.length; i++) {
          if (Math.random() < 0.01) {
            const amplitude = 0.2 + Math.random() * 0.4;
            const decay = 0.01 + Math.random() * 0.02;
            for (let j = 0; j < 100 && i + j < data.length; j++) {
              data[i + j] = amplitude * Math.exp(-j * decay);
            }
            i += 100;
          }
        }
        break;

      case 'leaves':
        // 树叶沙沙声：高频随机噪声
        for (let i = 0; i < data.length; i++) {
          // 高频噪声，模拟树叶摩擦声
          const noise = (Math.random() * 2 - 1) * 0.3;
          const freq = 2000 + Math.sin(i / 1000) * 500;
          data[i] = noise * 0.7 + 0.3 * Math.sin(2 * Math.PI * freq * i / this.audioContext.sampleRate) * Math.exp(-i / this.audioContext.sampleRate / 10);
        }
        break;

      case 'stream':
        // 溪流声：连续的白噪声
        for (let i = 0; i < data.length; i++) {
          // 白噪声加上轻微的低频波动
          const noise = (Math.random() * 2 - 1) * 0.4;
          const wave = 0.1 * Math.sin(2 * Math.PI * 100 * i / this.audioContext.sampleRate);
          data[i] = noise + wave;
        }
        break;

      case 'click':
        // 点击反馈音：短促的"滴"声
        for (let i = 0; i < this.audioContext.sampleRate * 0.1 && i < data.length; i++) {
          const t = i / this.audioContext.sampleRate;
          const freq = 1000 + 500 * Math.exp(-t * 20); // 频率从1000Hz下降到500Hz
          data[i] = 0.3 * Math.sin(2 * Math.PI * freq * t) * Math.exp(-t * 100);
        }
        break;

      case 'achievement':
        // 成就解锁音：上升音阶庆祝音效
        for (let i = 0; i < this.audioContext.sampleRate * 1.5 && i < data.length; i++) {
          const t = i / this.audioContext.sampleRate;
          // 上升的音阶：C4(261.63), E4(329.63), G4(392.00), C5(523.25)
          const notes = [261.63, 329.63, 392.00, 523.25];
          const noteIndex = Math.min(3, Math.floor(t * 3));
          const freq = notes[noteIndex];
          const envelope = Math.min(1, t * 5) * Math.exp(-t * 2); // 快速上升，缓慢衰减
          data[i] = 0.4 * Math.sin(2 * Math.PI * freq * t) * envelope;
        }
        break;

      default:
        // 默认：静音
        for (let i = 0; i < data.length; i++) {
          data[i] = 0;
        }
    }

    return buffer;
  },

  // 播放音效
  playSound(soundId, loop = null) {
    if (!this.audioContext || !this.config.enabled) return;

    // 确保音频上下文已恢复（移动端限制）
    const resumeAudio = () => {
      if (this.audioContext.state === 'suspended') {
        return this.audioContext.resume();
      }
      return Promise.resolve();
    };

    resumeAudio().then(() => {
      const sound = this.sounds[soundId];
      if (!sound) {
        // 尝试加载
        this.loadSound(soundId)
          .then(() => this.playSound(soundId, loop))
          .catch(error => console.warn(`🎧 播放音效失败: ${error}`));
        return;
      }

      // 停止当前播放的相同音效
      if (sound.source) {
        sound.source.stop();
      }

      // 创建新的音频源
      const source = this.audioContext.createBufferSource();
      source.buffer = sound.buffer;

      // 使用现有增益节点
      const gainNode = this.gainNodes[soundId];
      if (!gainNode) return;

      // 设置增益值
      gainNode.gain.value = sound.config.volume;

      // 连接：source -> gainNode -> masterGainNode
      source.connect(gainNode);

      // 设置循环
      source.loop = loop !== null ? loop : sound.config.loop;

      // 开始播放
      source.start(0);

      // 保存引用
      sound.source = source;

      // 更新播放状态
      this.isPlaying = true;
      this.updatePlayButtonState();

      // 设置结束回调（仅非循环音效）
      if (!source.loop) {
        source.onended = () => {
          sound.source = null;
        };
      }
    }).catch(error => {
      console.warn('🎧 恢复音频上下文失败:', error);
    });
  },



  // 停止音效
  stopSound(soundId) {
    const sound = this.sounds[soundId];
    if (sound && sound.source) {
      sound.source.stop();
      sound.source = null;
    }
  },

  // 开始环境音效
  startAmbientSounds() {
    if (!this.audioContext || !this.config.enabled) return;

    // 恢复音频上下文（移动端限制）
    const resumeAudio = () => {
      if (this.audioContext.state === 'suspended') {
        return this.audioContext.resume();
      }
      return Promise.resolve();
    };

    resumeAudio().then(() => {
      // 播放所有启用的音效
      Object.keys(this.config.sounds).forEach(soundId => {
        const soundConfig = this.config.sounds[soundId];
        if (soundConfig.loop && this.getSoundEnabledState(soundId)) {
          this.playSound(soundId, true);
        }
      });

      this.isPlaying = true;
      this.config.enabled = true;
      this.updatePlayButtonState();
      console.log('🎧 环境音效已开始播放');
    }).catch(error => {
      console.warn('🎧 恢复音频上下文失败:', error);
    });
  },

  // 停止所有音效
  stopAllSounds() {
    Object.keys(this.sounds).forEach(soundId => {
      this.stopSound(soundId);
    });

    this.isPlaying = false;
    this.config.enabled = false;
    this.updatePlayButtonState();
    console.log('🎧 所有音效已停止');
  },

