      '时光种子', '记忆根须'
    ];

    const plantName = plantNames[plantId - 1] || `森林植物 #${plantId}`;
    const plantEmoji = '🌿';

    this.showNotification(`${plantEmoji} 发现了新的植物：${plantName}！`);

